// =============================================================
// Build Prompt — resolve variables in prompt template
// =============================================================

const item = $input.first().json;
const { resolvedConfig, variableContext, tenantId } = item;

const prompt = resolvedConfig.prompt || '';
const outputSchema = resolvedConfig.output_schema || [];

// Build context string for LLM.
// CANONICAL SOURCE: apps/cms/features/workflows/engine/context-builder.ts (flattenContextForLlm)
// Changes here must be mirrored in the canonical TypeScript source.
// Logic: trigger fields flat, step namespace objects expanded one level, aiOutputJson skipped.
const contextEntries = [];
for (const [k, v] of Object.entries(variableContext)) {
  if (v !== null && typeof v === 'object' && !Array.isArray(v)) {
    // Step namespace object — flatten its fields
    for (const [fk, fv] of Object.entries(v)) {
      if (fk !== 'aiOutputJson') {
        contextEntries.push(`${fk}: ${JSON.stringify(fv)}`);
      }
    }
  } else {
    contextEntries.push(`${k}: ${JSON.stringify(v)}`);
  }
}
const contextString = contextEntries.join('\n');

return {
  json: {
    ...item,
    aiPayload: {
      prompt,
      context: contextString,
      output_schema: outputSchema,
      tenant_id: tenantId,
    },
  }
};

// =============================================================
// Save Input Payload — audit per attempt (T-209)
// =============================================================
// Save resolved AI prompt + context + output_schema BEFORE LLM call.
// Each retry attempt produces a fresh render via this same path.
// =============================================================

const https = require('https');

const SUPABASE_URL = $env.SUPABASE_URL;
if (!SUPABASE_URL) throw new Error('SUPABASE_URL environment variable not configured');
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;

// @inline supabase-request
async function supabaseRequest(path, method, body) {
  const url = `${SUPABASE_URL}/rest/v1/${path}`;
  return new Promise((resolve, reject) => {
    const match = url.match(/^https?:\/\/([^/]+)(\/.*)$/);
    if (!match) { reject(new Error('Invalid SUPABASE_URL')); return; }
    const options = {
      hostname: match[1],
      path: match[2],
      method: method || 'GET',
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=representation',
      },
    };
    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        if (res.statusCode >= 400) {
          reject(new Error(`Supabase ${method || 'GET'} ${path} ${res.statusCode}: ${data}`));
          return;
        }
        try {
          resolve(data ? JSON.parse(data) : null);
        } catch (e) {
          reject(new Error(`Parse error for ${path}: ${data}`));
        }
      });
    });
    req.on('error', reject);
    if (body !== undefined && body !== null) req.write(JSON.stringify(body));
    req.end();
  });
}
// @end-inline supabase-request

const item = $input.first().json;
const aiPayload = item.aiPayload || {};
const inputPayload = {
  prompt: aiPayload.prompt,
  context: aiPayload.context,
  output_schema: aiPayload.output_schema,
  tenant_id: aiPayload.tenant_id,
};

if (item.currentStepExecId) {
  await supabaseRequest(
    `workflow_step_executions?id=eq.${item.currentStepExecId}`,
    'PATCH',
    { input_payload: inputPayload }
  );
}

return { json: item };

// =============================================================
// Parse AI Result — extract structured output from MiniMax Agent
// =============================================================
// MiniMax returns: { content: [{ type: 'thinking', ... }, { type: 'text', text: '```json\n{...}\n```' }] }
// We need: find 'text' entry, strip markdown code fences, parse JSON.
// If output_schema is defined, map parsed JSON to ONLY the configured keys.
// =============================================================

function stripCodeFences(str) {
  const match = str.match(/```(?:json)?\s*([\s\S]*?)```/);
  return match ? match[1].trim() : str.trim();
}

function extractTextContent(aiOutput) {
  // Case 1: content array with typed entries (MiniMax/Claude format)
  if (aiOutput && Array.isArray(aiOutput.content)) {
    const textEntry = aiOutput.content.find(c => c.type === 'text');
    if (textEntry && textEntry.text) return textEntry.text;
    // Fallback: first entry with text
    const anyText = aiOutput.content.find(c => c.text);
    if (anyText) return anyText.text;
  }
  // Case 2: direct text field
  if (aiOutput && aiOutput.text) return aiOutput.text;
  // Case 3: stringified response
  return JSON.stringify(aiOutput);
}

try {
  const aiOutput = $('Call MiniMax Agent').first().json;
  const rawText = extractTextContent(aiOutput);
  const cleaned = stripCodeFences(rawText);

  let parsedOutput;
  let parsed;
  try {
    parsed = JSON.parse(cleaned);
  } catch {
    parsed = null;
  }

  if (parsed !== null) {
    // If output_schema is configured, map to ONLY the defined keys
    const item = $('Build Prompt').first().json;
    const schema = item.currentStep && item.currentStep.step_config && item.currentStep.step_config.output_schema;
    if (schema && Array.isArray(schema) && schema.length > 0) {
      const mapped = {};
      schema.forEach(field => {
        if (parsed[field.key] !== undefined) mapped[field.key] = parsed[field.key];
      });
      parsedOutput = Object.keys(mapped).length > 0 ? mapped : parsed;
    } else {
      parsedOutput = parsed;
    }
  } else {
    parsedOutput = { aiResponse: rawText };
  }

  // Always add aiOutputJson = aggregate of all mapped fields (object type).
  // Built from snapshot BEFORE adding itself — no circular reference.
  // Lets update_response map the whole result: ai_qualification → {{step.aiOutputJson}}
  const outputSnapshot = { ...parsedOutput };
  parsedOutput = { ...parsedOutput, aiOutputJson: outputSnapshot };

  const item = $('Build Prompt').first().json;
  return {
    json: {
      ...item,
      stepResult: {
        success: true,
        outputPayload: parsedOutput,
      },
    }
  };
} catch (e) {
  const item = $('Build Prompt').first().json;
  return {
    json: {
      ...item,
      stepResult: {
        success: false,
        error: `AI action failed: ${e.message}`,
      },
    }
  };
}
